// ============================================================
// MYTHWRIGHT — EXPORT UTILITIES
// Handles all export formats. Browser-native formats (JSON,
// Markdown, HTML, PNG) run client-side. Pandoc formats are
// generated by calling the /api/pandoc endpoint (or, in the
// desktop/self-hosted case, via a bundled Pandoc worker).
// ============================================================

import type { Outline, Beat, TipTapJSON } from '../types'

// ── Types ────────────────────────────────────────────────────
export type NativeFmt  = 'json' | 'markdown' | 'html' | 'png'
export type PandocFmt  =
  | 'docx' | 'odt' | 'rtf' | 'epub' | 'pdf'
  | 'rst'  | 'asciidoc' | 'org' | 'mediawiki' | 'textile'
  | 'latex' | 'man' | 'plain' | 'gfm' | 'jira' | 'dokuwiki'
  | 'fb2' | 'typst' | 'opendocument' | 'pptx'

export type ExportFormat = NativeFmt | PandocFmt

export interface ExportFormatMeta {
  id:          ExportFormat
  label:       string
  ext:         string
  mime:        string
  icon:        string
  group:       'native' | 'document' | 'web' | 'markup' | 'slides'
  description: string
  native?:     boolean   // runs in-browser, no server needed
}

